define([], function() { return { transport: function(selector, query, success, failure) { var url = M.cfg.wwwroot + '/local/solicitacoes/ajax/buscar-usuarios.php' + '?q=' + encodeURIComponent(query) + '&limit=30' + '&sesskey=' + encodeURIComponent(M.cfg.sesskey); var xhr = new XMLHttpRequest();
            xhr.open('GET', url, true);
            xhr.setRequestHeader('Accept', 'application/json');
            xhr.onload = function() { if (xhr.status >= 200 && xhr.status < 300) { try { var data = JSON.parse(xhr.responseText);
                        success(data); } catch (e) { failure(e); } } else { failure(new Error('HTTP ' + xhr.status)); } };
            xhr.onerror = function() { failure(new Error('Network error')); };
            xhr.send(); }, processResults: function(selector, results) { if (!Array.isArray(results)) { return []; } return results.map(function(user) { return { value: user.id, label: user.label || (user.fullname + ' (' + user.username + ')') }; }); } }; });